const data = $input.first().json;

if (!data.total || data.total === 0) {
  throw new Error('Aucun avis analysé trouvé pour cet établissement sur la période indiquée.');
}

const { center, period, forms, total } = data;

let prompt = `Établissement : ${center.name}\nPériode : ${period.from} → ${period.to}\nNombre total d'avis : ${total}\n\n`;

for (const [i, f] of forms.entries()) {
  const date = new Date(f.createdAt).toLocaleDateString('fr-FR');
  prompt += `### Avis ${i + 1} — ${date}`;
  if (f.averageRating !== null) prompt += ` — Note moyenne : ${f.averageRating}/5`;
  prompt += '\n';
  prompt += `Analyse : ${f.analysis.analyse}\n`;
  prompt += `Tags : ${f.analysis.tags.join(', ')}\n`;
  if (f.analysis.needsHumanReview) prompt += `⚠️ Relecture humaine recommandée\n`;
  prompt += '\n';
}

const title = `Pré-audit IA — ${center.name} (${period.from} → ${period.to})`;

return [{ json: { prompt, centerId: center.id, centerName: center.name, title } }];
